import os
from src.nodes.base import BaseNode

class FileReaderNode(BaseNode):
    name = "File Reader"

    def __init__(self):
        super().__init__()
        self.icon_path = "icons/folder.svg"
        # [AUTO-GENERATED-PORTS-START]
        self.add_input("file_path", "string", widget_type="file")
        self.add_output("content", "string")
        # [AUTO-GENERATED-PORTS-END]

    async def execute(self, inputs):
        path = inputs.get('file_path', '')
        if not os.path.exists(path):
            await self.set_output("exec_out", True)
            return {'content': ''}
        with open(path, 'r', encoding='utf-8') as f:
            return {'content': f.read()}

def register_node():
    return FileReaderNode
